1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const countLiveNeighbors = (
12	  liveCells: Cell[],
13	): Map<string, { cell: Cell; count: number }> => {
14	  const counts = new Map<string, { cell: Cell; count: number }>();
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const key = keyOf(neighbor);
19	      const entry = counts.get(key);
20	      if (entry) entry.count += 1;
21	      else counts.set(key, { cell: neighbor, count: 1 });
22	    }
23	  }
24	  return counts;
25	};
26	
27	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
28	  const liveKeys = new Set(liveCells.map(keyOf));
29	  const neighborCounts = countLiveNeighbors(liveCells);
30	
31	  const survives = (key: string, count: number): boolean =>
32	    count === 3 || (count === 2 && liveKeys.has(key));
33	
34	  const nextCells: Cell[] = [];
35	  for (const [key, { cell, count }] of neighborCounts) {
36	    if (survives(key, count)) nextCells.push(cell);
37	  }
38	  return nextCells;
39	};
